const Dashboard = ({
                       threads = [],
                       news = [],
                       matches = [],
                       events = []
                   }) => {
    return (
        <div style={styles.container}>
            <div style={styles.column}>
                <h2>Threads</h2>
                <ul>
                    {threads.map((thread, i) => (
                        <li key={i}>{thread.title}</li>
                    ))}
                </ul>
            </div>

            <div style={styles.column}>
                <h2>News</h2>
                <ul>
                    {news.map((article, i) => (
                        <li key={i}>{article.headline}</li>
                    ))}
                </ul>
            </div>

            <div style={styles.column}>
                <h2>Matches</h2>
                <ul>
                    {matches.map((match, i) => (
                        <li key={i}>
                            {match.teama} vs {match.teamb} — {new Date(match.match_time).toLocaleString()}
                        </li>
                    ))}
                </ul>
            </div>

            <div style={styles.column}>
                <h2>Events</h2>
                <ul>
                    {events.map((event, i) => (
                        <li key={i}>
                            {event.name} — {new Date(event.event_date_time).toLocaleString()}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
};
